	}

	// Content block (title, list, CTA, badges)
	.content-block {
		display: flex;
		flex-direction: column;
		gap: fonts.rem(24px);
		@media #{layout.$medium-screen-and-smaller} {
			padding-inline: fonts.rem(32px);
		}
		@media #{layout.$small-screen-only} {
			padding-inline: fonts.rem(16px);
