			gap: fonts.rem(16px);

			.title {
				font-family: fonts.$STIX-Two-Text;
				font-weight: 400;
				font-size: fonts.rem(54px);
				line-height: 1;
				letter-spacing: -1.08px;
				color: colors.$color-black;
				@media #{layout.$medium-screen-and-smaller} {
					font-size: fonts.rem(36px);
					letter-spacing: -0.72px;
				}
			}

			.subtitle {
				font-family: fonts.$DM-Sans;
				font-weight: 400;
				font-size: fonts.rem(22px);
				line-height: 1.4;
				letter-spacing: -0.16px;
				color: colors.$color-black;
				@media #{layout.$medium-screen-and-smaller} {
					font-weight: 500;
					font-size: fonts.rem(18px);
					letter-spacing: -0.36px;
				}
			}
		}

		// List items with left border
		.list-block {
			ul {
				list-style: none;
				margin: 0;
				padding: 0;
				display: flex;
				flex-direction: column;
				gap: fonts.rem(16px);
				@media #{layout.$medium-screen-and-smaller} {
					gap: fonts.rem(12px);
				}
			}

			li {
				border-left: 2px solid rgba(96, 91, 82, 0.2);
				padding-left: fonts.rem(12px);
				font-family: fonts.$DM-Sans;
				font-weight: 500;
				font-size: fonts.rem(22px);
				line-height: 1.1;
				letter-spacing: -0.44px;
				color: colors.$color-black;
				@media #{layout.$medium-screen-and-smaller} {
					font-size: fonts.rem(18px);
					letter-spacing: -0.36px;
					padding-left: fonts.rem(8px);
				}
			}
		}

		// CTA + badges
		.cta-block {
			display: flex;
			flex-direction: column;
			gap: fonts.rem(8px);

			.injections-cta-block {
				width: 100%;

				.cta-wrapper {
					width: 100%;
				}

				a {
					width: 100%;
					height: 48px;
					border-radius: 2px;
					padding: 0 fonts.rem(48px);
					box-sizing: border-box;
				}
			}

			.badges-wrapper {
				display: flex;
				flex-wrap: wrap;
				align-items: center;
				justify-content: center;
				gap: fonts.rem(10px);

				.badge {
					display: flex;
					align-items: center;
					height: 20px;

					img {
						width: auto;
						height: 24px;
					}

					span {
						font-family: fonts.$DM-Sans;
						font-weight: 400;
						font-size: fonts.rem(14px);
						line-height: 1.4;
						letter-spacing: -0.28px;
						color: colors.$color-gray;
						text-align: center;
					}
				}
			}
