			.faq-icon {
				display: flex;
				align-items: center;
				justify-content: center;
				width: 24px;
				height: 24px;
				flex-shrink: 0;
				position: relative;

				.icon-line {
					position: absolute;
					background-color: colors.$color-black;
					transition: transform 0.3s ease;
				}

				.line-horizontal {
					width: 24px;
					height: 1px;
				}

				.line-vertical {
					width: 1px;
					height: 24px;
				}
			}
		}

		.faq-content {
			max-height: 0;
			overflow: hidden;
			transition: max-height 0.4s ease;

			.faq-item-answer {
				padding: 0 0 fonts.rem(20px);
				font-family: fonts.$DM-Sans;
