				letter-spacing: -0.14px;
				color: colors.$color-black;
			}
		}

		// Open state
		.faq-item.open {
			.faq-icon {
				.line-horizontal {
					transform: rotate(45deg);
				}

				.line-vertical {
					transform: rotate(45deg);
				}
			}

			.faq-content {
				max-height: 500px;
			}
		}
	}
